import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API = 'http://localhost:5000';

function App() {
  const [user, setUser] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [amount, setAmount] = useState(0);
  const [type, setType] = useState('deposit');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    if (user) {
      axios.get(`${API}/api/transactions/${user._id}`).then(res => {
        setTransactions(res.data);
      });
    }
  }, [user]);

  const handleTransaction = async () => {
    await axios.post(`${API}/api/transactions`, {
      userId: user._id,
      amount: Number(amount),
      type,
    });
    await axios.post('/api/transactions', {
  userId: user._id,
  amount: Number(amount),
  type
});

// Re-fetch user to get updated balance
const updatedUser = await axios.post('/api/users/login', {
  email: user.email,
  password: user.password // must be saved when logging in
});
setUser(updatedUser.data);

// Re-fetch transactions
const txRes = await axios.get(`/api/transactions/${user._id}`);
setTransactions(txRes.data);
  };
  const handleLogin = async () => {
    try {
      const res = await axios.post(`${API}/api/users/login`, { email, password });
      setUser(res.data);
    } catch (err) {
      alert('Login failed');
    }
  };

  return (
    <div className="App">
      {!user ? (
        <div>
          <h2>Login</h2>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Email"
          />
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Password"
          />
          <button onClick={handleLogin}>Login</button>
        </div>
      ) : (
        <div>
          <h2>Welcome {user.name}</h2>
          <h3>Balance: ${user.balance}</h3>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="Amount"
          />
          <select value={type} onChange={(e) => setType(e.target.value)}>
            <option value="deposit">Deposit</option>
            <option value="withdrawal">Withdrawal</option>
          </select>
          <button onClick={handleTransaction}>Submit</button>

          <h4>Transaction History</h4>
          <ul>
            {transactions.map((t, i) => (
              <li key={i}>
                {t.type} - ${t.amount} on {new Date(t.date).toLocaleDateString()}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default App;
